// 1. Initialize an empty dictionary to store counts of each word.
// 2. Split the input string into words. We need to consider words as sequences of alphanumeric characters separated by non-alphanumeric characters.
// 3. Convert each word to lowercase to ensure case-insensitivity.
// 4. Count the frequency of each word.
// 5. Return the dictionary.

import Foundation

func wordCount(_ text: String) -> [String: Int] {
    // Split the string into words using CharacterSet for non-alphanumerics
    let words = text.components(separatedBy: CharacterSet.alphanumerics.inverted)
        .filter { !$0.isEmpty }
        .map { $0.lowercased() }

    // Count the frequency
    var counts = [String: Int]()
    for word in words {
        counts[word, default: 0] += 1
    }

    return counts
}

